import{_ as e,a as t,b as i}from"./chunks/支持留言.NiGCLVdp.js";import{_ as s,o as p,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"部落格使用說明","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Other/blog.md","filePath":"zh-TW/Other/blog.md","lastUpdated":1781962217000}'),n={name:"zh-TW/Other/blog.md"};function d(c,a,r,h,g,b){return p(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="部落格使用說明" tabindex="-1">部落格使用說明 <a class="header-anchor" href="#部落格使用說明" aria-label="Permalink to &quot;部落格使用說明&quot;">​</a></h1><p>部落格功能可以替 ImgBed 站台新增一個獨立部落格頁面。</p><p>啟用後，訪客可以透過：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://你的網域/blog/</span></span></code></pre></div><p>瀏覽部落格。</p><p><img src="'+e+'" alt="部落格首頁" loading="lazy"></p><p>部落格頁面改作自 <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a> 開源專案。感謝原專案開源，ImgBed 以 Vue 重寫並整合到目前圖床專案中。</p><h2 id="入口位置" tabindex="-1">入口位置 <a class="header-anchor" href="#入口位置" aria-label="Permalink to &quot;入口位置&quot;">​</a></h2><p>部落格設定在：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>系統設定 -&gt; 其他設定 -&gt; 部落格</span></span></code></pre></div><p><img src="'+t+'" alt="部落格設定" loading="lazy"></p><h2 id="第一次使用" tabindex="-1">第一次使用 <a class="header-anchor" href="#第一次使用" aria-label="Permalink to &quot;第一次使用&quot;">​</a></h2><ol><li>打開「啟用」開關。</li><li>選擇用來存放部落格設定的 GitHub 帳號。</li><li>點「更新部落格」。</li><li>等系統提示更新成功。</li><li>前往 <code>https://你的網域/blog/</code> 查看部落格。</li></ol><p>第一次使用時，系統會在你選的 GitHub 帳號下準備一個私有 repo：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>這個 repo 用來保存部落格設定和文章內容。</p><h2 id="怎麼寫文章" tabindex="-1">怎麼寫文章 <a class="header-anchor" href="#怎麼寫文章" aria-label="Permalink to &quot;怎麼寫文章&quot;">​</a></h2><p>文章內容在你自己的 GitHub 私有 repo 裡修改：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>常見流程：</p><ol><li>打開 GitHub。</li><li>進入 <code>imgbed-blog-config</code> 私有 repo。</li><li>修改或新增文章檔案。</li><li>Commit 儲存。</li><li>回 ImgBed 後台點「更新部落格」，或在部落格首頁左上角 Logo 連點三次觸發更新。</li></ol><p>「更新部落格」不會覆蓋你已經寫好的內容，主要用來初始化 repo 或刷新部落格快取。</p><h2 id="支援功能" tabindex="-1">支援功能 <a class="header-anchor" href="#支援功能" aria-label="Permalink to &quot;支援功能&quot;">​</a></h2><p>部落格支援文章列表、分類、標籤、封存、搜尋、深色模式、多語切換等常見功能。</p><p>也支援留言和瀏覽統計。</p><p><img src="'+i+'" alt="部落格留言" loading="lazy"></p><p>留言會顯示在文章下方。訪客可以填頭像、暱稱、Email 和留言內容後送出。</p><p>瀏覽統計會顯示文章瀏覽量、站台訪問次數等資訊，方便你了解部落格流量。</p><h2 id="訪問網址" tabindex="-1">訪問網址 <a class="header-anchor" href="#訪問網址" aria-label="Permalink to &quot;訪問網址&quot;">​</a></h2><p>部落格固定在 <code>/blog/</code> 路徑下。</p><p>例如你的 ImgBed 網域是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>部落格網址就是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>關閉部落格後，訪客將無法訪問部落格頁面。</p>',35)])])}const k=s(n,[["render",d]]);export{v as __pageData,k as default};
